UPDATE articles SET sections = '[{"id": "kas-yra-norton-360", "title": "Kas yra Norton 360?", "content": "<p><strong>Norton 360</strong> – tai vienas žinomiausių kibernetinio saugumo sprendimų pasaulyje, kuriamą kompanijos <strong>Gen Digital</strong> (anksčiau – NortonLifeLock / Symantec). Programinė įranga teikia visapusišką apsaugą nuo virusų, kenkėjiškos programinės įrangos, &bdquo;ransomware&ldquo; atakų, šnipinėjimo programų ir kitų internetinių grėsmių.</p><figure class=\"my-6\"><picture><source srcset=\"/images/reviews/norton/norton-pagrindinis-langas.webp\" type=\"image/webp\" /><img src=\"/images/reviews/norton/norton-pagrindinis-langas.png\" alt=\"Norton 360 pagrindinis langas\" class=\"rounded-lg border border-border/30 w-full\" loading=\"lazy\" /></picture><figcaption class=\"text-sm text-muted-foreground mt-2 text-center\">Norton 360 pagrindinis langas</figcaption></figure><p>Norton 360 išsiskiria tuo, kad tai nėra tik antivirusinė programa – tai <strong>pilnas saugumo paketas</strong>, apimantis:</p><ul><li><strong>Realaus laiko apsaugą</strong> nuo virusų ir kenkėjiškų programų</li><li><strong>Ugniasienę</strong> (Smart Firewall) tinklo apsaugai</li><li><strong>VPN</strong> (virtualų privatų tinklą) anoniminiam naršymui</li><li><strong>Slaptažodžių tvarkyklę</strong> prisijungimų valdymui</li><li><strong>Debesies atsarginę kopiją</strong> (iki 200 GB priklausomai nuo plano)</li><li><strong>Dark Web monitoringą</strong> – stebėjimą, ar jūsų duomenys nepateko į tamsiąją internetą</li><li><strong>SafeCam</strong> funkciją (tik Windows) – apsaugą nuo neleistinos prieigos prie jūsų kameros</li></ul><p>Programa palaiko <strong>Windows, macOS, Android ir iOS</strong> platformas. 2026 m. versijoje Norton dar labiau patobulintas AI variklis, kuris analizuoja grėsmes naudodamas mašininį mokymąsi.</p>"}, {"id": "diegimas-ir-naudojimas", "title": "Diegimas ir naudojimas", "content": "<p>Norton 360 diegimas yra <strong>paprastas ir intuityvus</strong> – visas procesas trunka apie 5–10 minučių.</p><figure class=\"my-6\"><picture><source srcset=\"/images/reviews/norton/norton-my-norton-hub.webp\" type=\"image/webp\" /><img src=\"/images/reviews/norton/norton-my-norton-hub.png\" alt=\"Norton My Norton valdymo centras\" class=\"rounded-lg border border-border/30 w-full\" loading=\"lazy\" /></picture><figcaption class=\"text-sm text-muted-foreground mt-2 text-center\">Norton My Norton valdymo centras</figcaption></figure><h3>Diegimo procesas žingsnis po žingsnio</h3><ol><li><strong>Paskyros sukūrimas</strong> – užsiregistruokite Norton svetainėje</li><li><strong>Plano pasirinkimas</strong> – išsirinkite tinkamą planą ir atlikite mokėjimą</li><li><strong>Diegimo failo atsisiuntimas</strong> – atsisiųskite programą iš &bdquo;My Norton&ldquo; portalo</li><li><strong>Įdiegimas</strong> – paleiskite diegimo failą ir sekite instrukcijas</li><li><strong>Pirmasis skenavimas</strong> – po diegimo programa automatiškai pasiūlys atlikti pilną sistemos patikrinimą</li></ol><h3>Vartotojo sąsaja</h3><p>Norton 360 sąsaja 2026 m. versijoje buvo <strong>ženkliai atnaujinta</strong>. Pagrindiniame lange matomas aiškus saugumo statusas – žalia spalva rodo, kad sistema apsaugota, o geltona/raudona indikuoja problemas.</p><ul><li><strong>&bdquo;Device Security&ldquo;</strong> – virusų skenavimas ir realaus laiko apsauga</li><li><strong>&bdquo;Online Privacy&ldquo;</strong> – VPN ir privatumo stebėjimas</li><li><strong>&bdquo;Identity&ldquo;</strong> – Dark Web monitoringas ir tapatybės apsauga</li><li><strong>&bdquo;Performance&ldquo;</strong> – sistemos optimizavimo įrankiai</li></ul><p>Naujiena – <strong>Norton Assistant</strong>, AI pagrindu veikiantis pagalbininkas, kuris pateikia saugumo rekomendacijas.</p><p><strong>Sistemos reikalavimai</strong>: Windows 10/11 (64-bit), 2 GB RAM, 300 MB disko vietos. macOS 13.0+. Android 9.0+ arba iOS 16.0+.</p>"}, {"id": "skenavimas-ir-apsauga", "title": "Skenavimas ir apsauga", "content": "<p>Norton 360 naudoja daugiasluoksnę apsaugos sistemą, kuri apjungia <strong>parašų duomenų bazę, heuristinę analizę ir dirbtinį intelektą (SONAR technologiją)</strong>.</p><figure class=\"my-6\"><picture><source srcset=\"/images/reviews/norton/norton-skenavimas.webp\" type=\"image/webp\" /><img src=\"/images/reviews/norton/norton-skenavimas.png\" alt=\"Norton 360 skenavimo langas\" class=\"rounded-lg border border-border/30 w-full\" loading=\"lazy\" /></picture><figcaption class=\"text-sm text-muted-foreground mt-2 text-center\">Norton 360 skenavimo langas</figcaption></figure><h3>Skenavimo tipai</h3><ul><li><strong>Greitas skenavimas</strong> – tikrina kritinius sistemos komponentus per 2–5 min.</li><li><strong>Pilnas skenavimas</strong> – kruopščiai tikrina visus failus ir procesus. Trunka 30–90 min.</li><li><strong>Pasirinktinis skenavimas</strong> – leidžia pasirinkti konkrečius aplankus</li><li><strong>Norton Power Eraser</strong> – agresyvus giluminis skenavimas sunkiau aptinkamoms grėsmėms</li></ul><h3>Nepriklausomų laboratorijų rezultatai</h3><table class=\"w-full border-collapse my-4\"><thead><tr class=\"bg-muted/40\"><th class=\"border border-border/30 px-4 py-2 text-left\">Laboratorija</th><th class=\"border border-border/30 px-4 py-2 text-left\">Testas</th><th class=\"border border-border/30 px-4 py-2 text-left\">Rezultatas</th></tr></thead><tbody><tr><td class=\"border border-border/30 px-4 py-2\">AV-TEST</td><td class=\"border border-border/30 px-4 py-2\">Apsauga</td><td class=\"border border-border/30 px-4 py-2\"><strong>6/6</strong> (puikiai)</td></tr><tr><td class=\"border border-border/30 px-4 py-2\">AV-TEST</td><td class=\"border border-border/30 px-4 py-2\">Našumas</td><td class=\"border border-border/30 px-4 py-2\"><strong>5.5/6</strong></td></tr><tr><td class=\"border border-border/30 px-4 py-2\">AV-Comparatives</td><td class=\"border border-border/30 px-4 py-2\">Realaus laiko apsauga</td><td class=\"border border-border/30 px-4 py-2\"><strong>99.7%</strong> aptikimas</td></tr><tr><td class=\"border border-border/30 px-4 py-2\">SE Labs</td><td class=\"border border-border/30 px-4 py-2\">Namų vartotojams</td><td class=\"border border-border/30 px-4 py-2\"><strong>AAA</strong> reitingas</td></tr></tbody></table><h3>Realaus laiko apsauga</h3><p>Norton veikia fone ir <strong>automatiškai tikrina kiekvieną atsisiunčiamą failą, el. pašto priedą ir lankomą svetainę</strong>:</p><ul><li><strong>SONAR</strong> – elgesio analizė</li><li><strong>Download Insight</strong> – reputacijos sistema</li><li><strong>Anti-phishing</strong> – sukčiavimo svetainių blokavimas</li></ul>"}, {"id": "funkcijos-ir-galimybes", "title": "Funkcijos ir galimybės", "content": "<p>Norton 360 siūlo <strong>vieną plačiausių funkcijų rinkinių</strong> tarp antivirusinių programų.</p><figure class=\"my-6\"><picture><source srcset=\"/images/reviews/norton/norton-secure-vpn.webp\" type=\"image/webp\" /><img src=\"/images/reviews/norton/norton-secure-vpn.png\" alt=\"Norton Secure VPN nustatymai\" class=\"rounded-lg border border-border/30 w-full\" loading=\"lazy\" /></picture><figcaption class=\"text-sm text-muted-foreground mt-2 text-center\">Norton Secure VPN nustatymai</figcaption></figure><figure class=\"my-6\"><picture><source srcset=\"/images/reviews/norton/norton-password-manager.webp\" type=\"image/webp\" /><img src=\"/images/reviews/norton/norton-password-manager.png\" alt=\"Norton Password Manager\" class=\"rounded-lg border border-border/30 w-full\" loading=\"lazy\" /></picture><figcaption class=\"text-sm text-muted-foreground mt-2 text-center\">Norton Password Manager</figcaption></figure><figure class=\"my-6\"><picture><source srcset=\"/images/reviews/norton/norton-safecam.webp\" type=\"image/webp\" /><img src=\"/images/reviews/norton/norton-safecam.png\" alt=\"Norton SafeCam apsauga\" class=\"rounded-lg border border-border/30 w-full\" loading=\"lazy\" /></picture><figcaption class=\"text-sm text-muted-foreground mt-2 text-center\">Norton SafeCam apsauga</figcaption></figure><h3>Slaptažodžių tvarkyklė (Norton Password Manager)</h3><p>Integruota slaptažodžių tvarkyklė leidžia <strong>saugiai saugoti ir automatiškai pildyti prisijungimo duomenis</strong>.</p><ul><li><strong>Slaptažodžių generatorius</strong> – sukuria stiprius, unikalius slaptažodžius</li><li><strong>Automatinis pildymas</strong> – prisijungimo formose automatiškai įveda kredencialus</li><li><strong>Saugumo ataskaita</strong> – analizuoja slaptažodžius ir nurodo silpnus ar pakartotinius</li><li><strong>Sinchronizacija</strong> – veikia visuose įrenginiuose</li></ul><h3>VPN (Norton Secure VPN)</h3><p>Užšifruoja internetinį srautą ir <strong>paslepia IP adresą</strong>.</p><ul><li><strong>AES-256 šifravimas</strong> su OpenVPN/IKEv2 protokolais</li><li><strong>No-log politika</strong></li><li><strong>Automatinis prijungimas</strong> prie nežinomo Wi-Fi</li><li><strong>30+ šalių</strong> serverių tinklas</li></ul><h3>SafeCam (tik Windows)</h3><p>Blokuoja <strong>neleistiną prieigą prie kameros</strong>. Praneša apie kiekvieną bandymą ir leidžia valdyti per baltąjį sąrašą.</p><h3>Dark Web monitoringas</h3><p>Stebi <strong>tamsiąją internetą</strong> ir ieško jūsų duomenų – el. pašto, telefonų, kortelių numerių.</p><ul><li><strong>24/7 stebėjimas</strong> – tikrina forumus ir nutekėjimų duomenų bazes</li><li><strong>Momentiniai pranešimai</strong> su veiksmų planu</li></ul><h3>Tėvų kontrolė (Norton Family)</h3><p>Su <strong>Deluxe</strong> ir <strong>Premium</strong> planais:</p><ul><li><strong>Turinio filtravimas</strong> – blokuoja netinkamas svetaines</li><li><strong>Ekrano laiko valdymas</strong></li><li><strong>GPS vietos stebėjimas</strong></li><li><strong>Mokymosi laiko režimas</strong></li></ul>"}, {"id": "saugumas-ir-nasumas", "title": "Saugumas ir našumas", "content": "<p>Viena dažniausių problemų su antivirusinėmis programomis – <strong>sistemos sulėtinimas</strong>. Norton 360 2026 m. versija šiuo atžvilgiu padarė didelę pažangą.</p><h3>Poveikis sistemos našumui</h3><table class=\"w-full border-collapse my-4\"><thead><tr class=\"bg-muted/40\"><th class=\"border border-border/30 px-4 py-2 text-left\">Veiksmas</th><th class=\"border border-border/30 px-4 py-2 text-left\">Sulėtinimas</th></tr></thead><tbody><tr><td class=\"border border-border/30 px-4 py-2\">Programų paleidimas</td><td class=\"border border-border/30 px-4 py-2\"><strong>2–5%</strong> (minimalus)</td></tr><tr><td class=\"border border-border/30 px-4 py-2\">Failų kopijavimas</td><td class=\"border border-border/30 px-4 py-2\"><strong>3–8%</strong></td></tr><tr><td class=\"border border-border/30 px-4 py-2\">Svetainių krovimas</td><td class=\"border border-border/30 px-4 py-2\"><strong>1–3%</strong></td></tr><tr><td class=\"border border-border/30 px-4 py-2\">Sistemos paleidimas</td><td class=\"border border-border/30 px-4 py-2\"><strong>5–10%</strong></td></tr></tbody></table><p>Norton naudoja <strong>debesų kompiuteriją</strong> – didelė dalis analizės atliekama serveriuose, kas sumažina apkrovą vartotojo kompiuteriui.</p>"}, {"id": "kainos-ir-planai", "title": "Kainos ir planai", "content": "<p>Norton 360 siūlo <strong>keturis pagrindinius planus</strong>, skirtus skirtingiems poreikiams.</p><h3>Planų palyginimas</h3><table class=\"w-full border-collapse my-4\"><thead><tr class=\"bg-muted/40\"><th class=\"border border-border/30 px-4 py-2 text-left\">Savybė</th><th class=\"border border-border/30 px-4 py-2 text-center\">Standard</th><th class=\"border border-border/30 px-4 py-2 text-center\">Deluxe</th><th class=\"border border-border/30 px-4 py-2 text-center\">Premium</th><th class=\"border border-border/30 px-4 py-2 text-center\">Ultra</th></tr></thead><tbody><tr><td class=\"border border-border/30 px-4 py-2\">Įrenginiai</td><td class=\"border border-border/30 px-4 py-2 text-center\"><strong>1</strong></td><td class=\"border border-border/30 px-4 py-2 text-center\"><strong>5</strong></td><td class=\"border border-border/30 px-4 py-2 text-center\"><strong>10</strong></td><td class=\"border border-border/30 px-4 py-2 text-center\"><strong>Neribotai</strong></td></tr><tr><td class=\"border border-border/30 px-4 py-2\">Debesies saugykla</td><td class=\"border border-border/30 px-4 py-2 text-center\">10 GB</td><td class=\"border border-border/30 px-4 py-2 text-center\">50 GB</td><td class=\"border border-border/30 px-4 py-2 text-center\">200 GB</td><td class=\"border border-border/30 px-4 py-2 text-center\">500 GB</td></tr><tr><td class=\"border border-border/30 px-4 py-2\">VPN</td><td class=\"border border-border/30 px-4 py-2 text-center\">✓</td><td class=\"border border-border/30 px-4 py-2 text-center\">✓</td><td class=\"border border-border/30 px-4 py-2 text-center\">✓</td><td class=\"border border-border/30 px-4 py-2 text-center\">✓</td></tr><tr><td class=\"border border-border/30 px-4 py-2\">Dark Web monitoringas</td><td class=\"border border-border/30 px-4 py-2 text-center\">✓</td><td class=\"border border-border/30 px-4 py-2 text-center\">✓</td><td class=\"border border-border/30 px-4 py-2 text-center\">✓</td><td class=\"border border-border/30 px-4 py-2 text-center\">✓</td></tr><tr><td class=\"border border-border/30 px-4 py-2\">Tėvų kontrolė</td><td class=\"border border-border/30 px-4 py-2 text-center\">–</td><td class=\"border border-border/30 px-4 py-2 text-center\">✓</td><td class=\"border border-border/30 px-4 py-2 text-center\">✓</td><td class=\"border border-border/30 px-4 py-2 text-center\">✓</td></tr><tr><td class=\"border border-border/30 px-4 py-2\">SafeCam</td><td class=\"border border-border/30 px-4 py-2 text-center\">✓</td><td class=\"border border-border/30 px-4 py-2 text-center\">✓</td><td class=\"border border-border/30 px-4 py-2 text-center\">✓</td><td class=\"border border-border/30 px-4 py-2 text-center\">✓</td></tr><tr class=\"bg-primary/5\"><td class=\"border border-border/30 px-4 py-2 font-semibold\">Kaina per metus</td><td class=\"border border-border/30 px-4 py-2 text-center font-bold\">~39,99 €</td><td class=\"border border-border/30 px-4 py-2 text-center font-bold\">~49,99 €</td><td class=\"border border-border/30 px-4 py-2 text-center font-bold\">~69,99 €</td><td class=\"border border-border/30 px-4 py-2 text-center font-bold\">~99,99 €</td></tr></tbody></table><p><strong>Svarbu:</strong> nurodytos kainos yra pirmųjų metų akcijinės kainos. Atsinaujinus prenumeratai, kainos paprastai padidėja <strong>2–3 kartus</strong>.</p><h3>Mūsų rekomendacija</h3><p>Daugumai vartotojų rekomenduojame <strong>Norton 360 Deluxe</strong> – optimaliausias kainos ir kokybės santykis su 5 įrenginių apsauga ir visomis svarbiausiomis funkcijomis.</p>"}, {"id": "mobilioji-programa", "title": "Mobilioji programa", "content": "<p>Norton 360 mobilioji programa pasiekiama <strong>Android</strong> ir <strong>iOS</strong> platformose.</p><h3>Android versija</h3><ul><li><strong>App Advisor</strong> – tikrina programas prieš ir po įdiegimo</li><li><strong>Wi-Fi saugumo tikrinimas</strong></li><li><strong>Svetainių apsauga</strong> nuo sukčiavimo</li><li><strong>SIM kortelės blokavimo pranešimai</strong></li></ul><h3>iOS versija</h3><ul><li><strong>Wi-Fi saugumo skenavimas</strong></li><li><strong>Turinio filtravimas</strong></li><li><strong>VPN</strong></li><li><strong>SMS saugumo tikrinimas</strong> – nauja 2026 m. funkcija</li></ul>"}, {"id": "palaikymas-ir-pagalba", "title": "Palaikymas ir pagalba", "content": "<p>Norton teikia <strong>platų pagalbos spektrą</strong>:</p><figure class=\"my-6\"><picture><source srcset=\"/images/reviews/norton/norton-pagalbos-centras.webp\" type=\"image/webp\" /><img src=\"/images/reviews/norton/norton-pagalbos-centras.png\" alt=\"Norton pagalbos centras\" class=\"rounded-lg border border-border/30 w-full\" loading=\"lazy\" /></picture><figcaption class=\"text-sm text-muted-foreground mt-2 text-center\">Norton pagalbos centras</figcaption></figure><ul><li><strong>24/7 telefono palaikymas</strong></li><li><strong>Tiesioginiai pokalbiai (Live Chat)</strong> – greičiausias būdas</li><li><strong>Žinių bazė</strong> – straipsniai ir instrukcijos</li><li><strong>Norton bendruomenės forumas</strong></li></ul><p>Anglų kalba palaikymas veikia <strong>puikiai</strong>. Lietuvių kalba – ribotai, bet galima gauti pagalbą anglų kalba.</p>"}, {"id": "privatumas", "title": "Privatumas", "content": "<p>Norton renka tam tikrus <strong>diagnostinius ir naudojimo duomenis</strong>.</p><figure class=\"my-6\"><picture><source srcset=\"/images/reviews/norton/norton-email-apsauga.webp\" type=\"image/webp\" /><img src=\"/images/reviews/norton/norton-email-apsauga.png\" alt=\"Norton el. pašto apsauga\" class=\"rounded-lg border border-border/30 w-full\" loading=\"lazy\" /></picture><figcaption class=\"text-sm text-muted-foreground mt-2 text-center\">Norton el. pašto apsauga</figcaption></figure><ul><li>Duomenys naudojami <strong>grėsmių analizei ir produkto gerinimui</strong></li><li>VPN: oficiali <strong>no-log politika</strong> (neregistruoja naršymo istorijos)</li><li>Galima <strong>atsisakyti dalies duomenų rinkimo</strong> nustatymuose</li><li>Atitinka <strong>GDPR</strong> reikalavimus</li></ul>"}, {"id": "verdiktas", "title": "Verdiktas", "content": "<figure class=\"my-6\"><picture><source srcset=\"/images/reviews/norton/norton-nustatymai.webp\" type=\"image/webp\" /><img src=\"/images/reviews/norton/norton-nustatymai.png\" alt=\"Norton 360 nustatymų langas\" class=\"rounded-lg border border-border/30 w-full\" loading=\"lazy\" /></picture><figcaption class=\"text-sm text-muted-foreground mt-2 text-center\">Norton 360 nustatymų langas</figcaption></figure><p><strong>Norton 360</strong> yra vienas <strong>geriausių ir išsamiausių saugumo paketų</strong> rinkoje. Su puikiais nepriklausomų laboratorijų rezultatais (6/6 AV-TEST, AAA SE Labs), plačiausiu funkcijų rinkiniu (VPN, slaptažodžių tvarkyklė, Dark Web monitoringas, SafeCam, debesies atsarginės kopijos) ir patobulinta AI varikliu – tai sprendimas, kuris <strong>tinka tiek pradedantiesiems, tiek pažengusiems vartotojams</strong>.</p><p>Pagrindinis trūkumas – <strong>kaina po pirmo metų ženkliai padidėja</strong>, todėl verta sekti akcijas ir nuolaidas. Taip pat Linux vartotojai neturės galimybės naudoti Norton 360.</p><p>Jei ieškote <strong>visapusiško, patikimo ir lengvo naudoti saugumo sprendimo</strong> – Norton 360 yra puikus pasirinkimas. Rekomenduojame <strong>Deluxe</strong> planą kaip optimaliausią variantą.</p>"}]'::jsonb WHERE slug = 'norton-360-apzvalga';